const NET_CALORIFIC_VALUE = 0.0156;

function calc_fuel_type_rb(document) {
    if (document.G5 === 'Kerosene') {
        document.G6 = 71.9;
        document.G7 = 0.01;
        document.G8 = 0.0006;
    } else if (document.G5 === 'Coal') {
        document.G6 = 94.6;
        document.G7 = 0.3;
        document.G8 = 0.0015;
    } else {
        throw new Error(`Unknown option G5: ${document.G5}`);
    }
    document.G9 = 28;
    document.G10 = 265;
    return document;
}

function calc_project_device_rb(document) {
    document.G8 = calc_fuel_type_rb(document.G8);
    document.G7 =
        document.G8.G6 +
        document.G8.G7 * document.G8.G9 +
        document.G8.G8 * document.G8.G10;
    return document;
}

function calc_batch_of_project_devices_rb(document) {
    document.G6 = calc_project_device_rb(document.G6);
    return document;
}

function calc_project_emission_reductions_rb(document) {
    document.G13 = document.G13.map((item) =>
        calc_batch_of_project_devices_rb(item)
    );
    document.G9 = (document.tool_16.C71 || 0) + (document.tool_16.C73 || 0);
    document.G10 = (document.tool_16.C104 || 0) + (document.tool_16.C74 || 0);
    document.G11 = 0;
    document.G12 =
        (document.tool_16.C136 || 0) +
        (document.tool_16.C119 || 0) +
        (parseFloat(document.tool_16.C112?.C116) || 0);
    document.G5 =
        document.G13.reduce(
            (sum, item) => sum + item.G5 * item.G6.G5 * item.G6.G6 * item.G6.G7,
            0
        ) *
            document.G7 *
            document.G8 *
            document.G6 -
        document.G9 -
        document.G10 -
        document.G11 -
        document.G12;
    return document;
}

function calc_project_device_nr(document) {
    document.G9 = document.G27 * document.G28 * 3.6 * Math.pow(10, -6);
    if (document.G12 === 'Yes') {
        document.G13 = document.tool_33_G13.field1;
        document.G15 = document.G13;
    } else if (document.G12 === 'No') {
        document.G15 = document.G14;
    } else {
        throw new Error(`Unknown option G12: ${document.G12}`);
    }
    document.G11 = document.G15 * document.G16;
    document.G10 = document.G11 / document.G17;

    if (document.G20 === 'Yes') {
        document.G21 = document.tool_33_G21.field1;
        document.G23 = document.G21;
    } else if (document.G20 === 'No') {
        document.G23 = document.G22;
    } else {
        throw new Error(`Unknown option G20: ${document.G20}`);
    }

    switch (document.G6) {
        case 'Thermal Energy Output (TEO)':
            document.G8 =
                (document.G9 / NET_CALORIFIC_VALUE) *
                (1 / document.G23 - 1 / document.G24);
            break;
        case 'Kitchen performance test (KPT)':
            document.G8 = document.G10 - document.G18;
            break;
        case 'Water boiling test (WBT)': {
            if (document.G7 === 'Equation 7') {
                document.G8 = document.G10 * (1 - document.G24 / document.G23);
            } else if (document.G7 === 'Equation 8') {
                document.G8 = document.G19 * (document.G24 / document.G23 - 1);
            } else {
                throw new Error(`Unknown option G7: ${document.G7}`);
            }
            break;
        }
        case 'Controlled cooking test (CCT)':
            document.G8 = document.G10 * (1 - document.G26 / document.G25);
            break;
        default:
            throw new Error(`Unknown option G6: ${document.G6}`);
    }
    return document;
}

function calc_batch_of_project_devices_nr(document) {
    document.G6 = calc_project_device_nr(document.G6);
    return document;
}

function calc_project_emission_reductions_nr(document) {
    document.G14 = document.G14.map((item) =>
        calc_batch_of_project_devices_nr(item)
    );
    document.G8 = NET_CALORIFIC_VALUE;
    if (document.G6 === 'TOOL30') {
        document.G7 = document.tool_30.field0;
    } else if (document.G6 === 'TOOL33') {
        document.G7 = document.tool_33.field1;
    } else {
        throw new Error(`Unknown option G6: ${document.G6}`);
    }

    document.G5 =
        document.G14.reduce(
            (sum, item) => sum + item.G5 * item.G6.G5 * item.G6.G8,
            0
        ) *
        document.G9 *
        document.G7 *
        document.G8 *
        (document.G10 + document.G11) *
        document.G12 *
        (1 - document.G13);
    return document;
}

function calc_er_determination(document) {
    if (document.G5 === 'Yes') {
        document.G7 = calc_project_emission_reductions_rb(document.G7);
        document.G8 = document.G7.G5;
    } else if (document.G5 === 'No') {
        document.G6 = calc_project_emission_reductions_nr(document.G6);
        document.G8 = document.G6.G5;
    } else {
        throw new Error(`Unknown option G5: ${document.G5}`);
    }
    return document;
}

function calc() {
    const document = documents[0].document.credentialSubject[0];

    document.field2 = calc_er_determination(document.field2);

    delete document['@context'];
    delete document['type'];
    delete document['id'];

    done(adjustValues(document));
}
calc();

function adjustValues(document) {
    const keys = Object.keys(document);
    for (const key of keys) {
        if (document[key] === undefined) {
            delete document[key];
        }
        if (typeof document[key] === 'number') {
            document[key] = isFinite(document[key]) ? document[key] : 0;
        }
        if (Array.isArray(document[key])) {
            for (const i in document[key]) {
                if (typeof document[key][i] === 'number') {
                    document[key][i] = isFinite(document[key][i])
                        ? document[key][i]
                        : 0;
                }
                if (
                    Object.prototype.toString.call(document[key][i]) ===
                    '[object Object]'
                ) {
                    document[key][i] = adjustValues(document[key][i]);
                }
            }
        }
        if (
            Object.prototype.toString.call(document[key]) === '[object Object]'
        ) {
            document[key] = adjustValues(document[key]);
        }
    }

    return document;
}

